139	    .clka(clock),
140	    .ena(1),
141	    .wea(lts_in_stb),
142	    .addra(lts_waddr),
143	    .dia({lts_i_in, lts_q_in}),
144	    .doa(),
145	    .clkb(clock),
146	    .enb(1),
147	    .web(1'b0),
148	    .addrb(lts_raddr[5:0]),
149	    .dib(32'hFFFF),
150	    .dob({lts_i_out, lts_q_out})
151	);
152	
153	calc_mean lts_i_inst (
154	    .clock(clock),
155	    .enable(enable),
156	    .reset(reset),
157	    
158	    .a(lts_i_out),
159	    .b(input_i),
160	    .sign(current_sign),
161	    .input_strobe(calc_mean_strobe),
162	
163	    .c(new_lts_i),
164	    .output_strobe(new_lts_stb)
165	);
166	
167	calc_mean lts_q_inst (
168	    .clock(clock),
169	    .enable(enable),
170	    .reset(reset),
171	    
172	    .a(lts_q_out),
173	    .b(input_q),
174	    .sign(current_sign),
175	    .input_strobe(calc_mean_strobe),
176	
177	    .c(new_lts_q)
178	);
179	
180	ram_2port  #(.DWIDTH(32), .AWIDTH(6)) in_buf_inst (
181	    .clka(clock),
182	    .ena(1),
183	    .wea(sample_in_strobe),
184	    .addra(in_waddr),
185	    .dia(sample_in),
186	    .doa(),
187	    .clkb(clock),
188	    .enb(1),
189	    .web(1'b0),
190	    .addrb(in_raddr[5:0]),
191	    .dib(32'hFFFF),
192	    .dob({buf_i_out, buf_q_out})
193	);
194	
195	complex_mult pilot_inst (
196	    .clock(clock),
197	    .enable(enable),
198	    .reset(reset),
199	    .a_i(input_i),
200	    .a_q(input_q),
201	    .b_i(lts_i_out),
202	    .b_q(lts_q_out),
203	    .input_strobe(pilot_in_stb),
204	    .p_i(pilot_i),
205	    .p_q(pilot_q),
206	    .output_strobe(pilot_out_stb)
207	);
208	
209	rotate rotate_inst (
210	    .clock(clock),
211	    .enable(enable),
212	    .reset(reset),
213	
214	    .in_i(buf_i_out),
215	    .in_q(buf_q_out),
216	    .phase(pilot_phase),
217	    .input_strobe(rot_in_stb),
218	
219	    .rot_addr(rot_addr),
220	    .rot_data(rot_data),
221	    
222	    .out_i(rot_i),
223	    .out_q(rot_q),
224	    .output_strobe(rot_out_stb)
225	);
226	
227	complex_mult input_lts_prod_inst (
228	    .clock(clock),
229	    .enable(enable),
230	    .reset(reset),
231	    .a_i(rot_i),
232	    .a_q(rot_q),
233	    .b_i(lts_i_out),
234	    .b_q(lts_q_out_neg),
235	    .input_strobe(rot_out_stb),
236	    .p_i(prod_i),
237	    .p_q(prod_q),
238	    .output_strobe(prod_out_strobe)
239	);
240	
241	complex_mult lts_lts_prod_inst (
242	    .clock(clock),
243	    .enable(enable),
244	    .reset(reset),
245	    .a_i(lts_i_out),
246	    .a_q(lts_q_out),
247	    .b_i(lts_i_out),
248	    .b_q(lts_q_out_neg),
249	    .input_strobe(rot_out_stb),
250	    .p_i(mag_sq)
251	);
252	
253	divider norm_i_inst (
254	    .clock(clock),
255	    .enable(enable),
256	    .reset(reset),
257	
258	    .dividend(prod_i_scaled),
259	    .divisor(mag_sq[23:0]),
260	    .input_strobe(prod_out_strobe),
261	
262	    .quotient(norm_i),
263	    .output_strobe(norm_out_stb)
264	);
265	
266	divider norm_q_inst (
267	    .clock(clock),
268	    .enable(enable),
269	    .reset(reset),
270	
271	    .dividend(prod_q_scaled),
272	    .divisor(mag_sq[23:0]),
273	    .input_strobe(prod_out_strobe),
274	
275	    .quotient(norm_q)
276	);
277	
278	localparam S_FIRST_LTS = 0;
279	localparam S_SECOND_LTS = 1;
280	localparam S_GET_POLARITY = 2;
281	localparam S_CALC_FREQ_OFFSET = 3;
282	localparam S_ADJUST_FREQ_OFFSET = 4;
283	localparam S_HT_LTS = 5;
284	
285	always @(posedge clock) begin
286	    if (reset) begin
287	        sample_out_strobe <= 0;
288	        lts_raddr <= 0;
289	        lts_waddr <= 0;
290	        sample_out <= 0;
291	
292	        lts_in_stb <= 0;
293	        lts_i_in <= 0;
294	        lts_q_in <= 0;
295	
296	        ht <= 0;
297	        num_data_carrier <= 48;
298	
299	        subcarrier_mask <= SUBCARRIER_MASK;
300	        data_subcarrier_mask <= DATA_SUBCARRIER_MASK;
301	        pilot_mask <= PILOT_MASK;
302	        lts_ref <= LTS_REF;
303	        ht_lts_ref <= HT_LTS_REF;
304	        polarity <= POLARITY;
305	
306	        ht_polarity <= HT_POLARITY;
307	
308	        current_polarity <= 0;
309	        pilot_count <= 0;
310	
311	        in_waddr <= 0;
312	        in_raddr <= 0;
313	
314	        phase_in_stb <= 0;
315	        pilot_sum_i <= 0;
316	        pilot_sum_q <= 0;
317	        pilot_phase <= 0;
318	        pilot_in_stb <= 0;
319	
320	        prod_in_strobe <= 0;
321	
322	        rot_in_stb <= 0;
323	
324	        current_sign <= 0;
325	        input_i <= 0;
326	        input_q <= 0;
327	        calc_mean_strobe <= 0;
328	
329	        num_output <= 0;
330	
331	        state <= S_FIRST_LTS;
332	    end else if (enable) begin
333	        case(state)
334	            S_FIRST_LTS: begin
335	                // store first LTS as is
336	                lts_in_stb <= sample_in_strobe;
337	                {lts_i_in, lts_q_in} <= sample_in;
338	
339	                if (lts_in_stb) begin
340	                    if (lts_waddr == 63) begin
341	                        lts_waddr <= 0;
342	                        lts_raddr <= 0;
343	                        state <= S_SECOND_LTS;
344	                    end else begin
345	                        lts_waddr <= lts_waddr + 1;
346	                    end
347	                end
348	            end
349	
350	            S_SECOND_LTS: begin
351	                // calculate and store the mean of the two LTS
352	                if (sample_in_strobe) begin
353	                    calc_mean_strobe <= sample_in_strobe;
354	                    {input_i, input_q} <= sample_in;
355	                    current_sign <= lts_ref[0];
356	                    lts_ref <= {lts_ref[0], lts_ref[63:1]};
357	                    lts_raddr <= lts_raddr + 1;
358	                end else begin
359	                    calc_mean_strobe <= 0;
360	                end
361	
362	                lts_in_stb <= new_lts_stb;
363	                {lts_i_in, lts_q_in} <= {new_lts_i, new_lts_q};
364	
365	                if (lts_in_stb) begin
366	                    if (lts_waddr == 63) begin
367	                        lts_waddr <= 0;
368	                        state <= S_GET_POLARITY;
369	                    end else begin
370	                        lts_waddr <= lts_waddr + 1;
371	                    end
372	                end
373	            end 
374	
375	            S_GET_POLARITY: begin
376	                // obtain the polarity of pilot sub-carriers for next OFDM symbol
377	                if (ht) begin
378	                    current_polarity <= {
379	                        ht_polarity[1]^polarity[0], // -7
380	                        ht_polarity[0]^polarity[0], // -21
381	                        ht_polarity[3]^polarity[0], // 21
382	                        ht_polarity[2]^polarity[0]  // 7
383	                        };
384	                    ht_polarity <= {ht_polarity[0], ht_polarity[3:1]};
385	                end else begin
386	                    current_polarity <= {
387	                        polarity[0],    // -7
388	                        polarity[0],    // -21
389	                        ~polarity[0],   // 21
390	                        polarity[0]     // 7
391	                        };
392	                end
393	                polarity <= {polarity[0], polarity[126:1]};
394	
395	                pilot_sum_i <= 0;
396	                pilot_sum_q <= 0;
397	                pilot_count <= 0;
398	                in_waddr <= 0;
399	                in_raddr <= 0;
400	                input_i <= 0;
401	                input_q <= 0;
402	                lts_raddr <= 0;
403	                state <= S_CALC_FREQ_OFFSET;
404	            end
405	
406	            S_CALC_FREQ_OFFSET: begin
407	                if (~ht & ht_next) begin
408	                    ht <= 1;
409	                    num_data_carrier <= 52;
410	                    lts_waddr <= 0;
411	                    lts_ref <= HT_LTS_REF;
412	                    subcarrier_mask <= HT_SUBCARRIER_MASK;
413	                    data_subcarrier_mask <= HT_DATA_SUBCARRIER_MASK;
414	                    pilot_mask <= PILOT_MASK;
415	                    // reverse this extra shift
416	                    polarity <= {polarity[125:0], polarity[126]};
417	                    state <= S_HT_LTS;
418	                end
419	
420	                // calculate residue freq offset using pilot sub carriers
421	                if (sample_in_strobe) begin
422	                    in_waddr <= in_waddr + 1;
423	                    lts_raddr <= lts_raddr + 1;
424	
425	                    pilot_mask <= {pilot_mask[0], pilot_mask[63:1]};
426	                    if (pilot_mask[0]) begin
427	                        pilot_count <= pilot_count + 1;
428	                        current_polarity <= {current_polarity[0],
429	                            current_polarity[3:1]};
430	                        // obtain the conjugate of current pilot sub carrier
431	                        if (current_polarity[0] == 0) begin
432	                            input_i <= sample_in[31:16];
433	                            input_q <= ~sample_in[15:0] + 1;
434	                        end else begin
435	                            input_i <= ~sample_in[31:16] + 1;
436	                            input_q <= sample_in[15:0];
437	                        end
438	                        pilot_in_stb <= 1;
439	                    end else begin
440	                        pilot_in_stb <= 0;
441	                    end
442	                end else begin
443	                    pilot_in_stb <= 0;
444	                end
445	
446	                if (pilot_out_stb) begin
447	                    pilot_sum_i <= pilot_sum_i + pilot_i;
448	                    pilot_sum_q <= pilot_sum_q + pilot_q;
449	                    if (pilot_count == 4) begin
450	                        phase_in_stb <= 1;
451	                    end else begin
452	                        phase_in_stb <= 0;
453	                    end
454	                end else begin
455	                    phase_in_stb <= 0;
456	                end
457	
458	                if (phase_out_stb) begin
459	                    `ifdef DEBUG_PRINT
460	                        $display("[PILOT OFFSET] %d", phase_out);
461	                    `endif
462	                    pilot_phase <= phase_out;
463	                    in_raddr <= 0;
464	                    // compensate for RAM read delay
465	                    lts_raddr <= 1;
466	                    rot_in_stb <= 0;
467	                    num_output <= 0;
468	                    state <= S_ADJUST_FREQ_OFFSET;
469	                end
470	            end
471	
472	            S_ADJUST_FREQ_OFFSET: begin
473	                // first rotate, then normalize by avg LTS
474	                if (in_raddr < 64) begin
475	                    in_raddr <= in_raddr + 1;
476	                    rot_in_stb <= 1;
477	                end else begin
478	                    rot_in_stb <= 0;
479	                end
480	
481	                if (rot_out_stb) begin
482	                    lts_raddr <= lts_raddr + 1;
483	                end
484	
485	                if (norm_out_stb) begin
486	                    data_subcarrier_mask <= {data_subcarrier_mask[0],
487	                        data_subcarrier_mask[63:1]};
488	                    if (data_subcarrier_mask[0]) begin
489	                        sample_out_strobe <= 1;
490	                        sample_out <= {norm_i[31], norm_i[14:0],
491	                            norm_q[31], norm_q[14:0]};
492	                        num_output <= num_output + 1;
493	                    end else begin
494	                        sample_out_strobe <= 0;
495	                    end
496	                end else begin
497	                    sample_out_strobe <= 0;
498	                end
499	
500	                if (num_output == num_data_carrier) begin
501	                    state <= S_GET_POLARITY;
502	                end
503	            end
504	
505	            S_HT_LTS: begin
506	                if (sample_in_strobe) begin
507	                    lts_in_stb <= 1;
508	                    ht_lts_ref <= {ht_lts_ref[0], ht_lts_ref[63:1]};
509	                    if (ht_lts_ref[0] == 0) begin
510	                        {lts_i_in, lts_q_in} <= sample_in;
511	                    end else begin
512	                        lts_i_in <= ~sample_in[31:16]+1;
513	                        lts_q_in <= ~sample_in[15:0]+1;
514	                    end
515	                end else begin
516	                    lts_in_stb <= 0;
517	                end
518	
519	                if (lts_in_stb) begin
520	                    if (lts_waddr == 63) begin
521	                        lts_waddr <= 0;
522	                        lts_raddr <= 0;
523	                        state <= S_GET_POLARITY;
524	                    end else begin
525	                        lts_waddr <= lts_waddr + 1;
526	                    end
527	                end
528	
529	            end
530	
531	            default: begin
532	                state <= S_FIRST_LTS;
533	            end
534	        endcase
535	    end else begin
536	        sample_out_strobe <= 0;
537	    end
538	end
539	
540	endmodule
